function flattenKeys(obj, prefix) {
  prefix = prefix || '';
  const result = {};
  for (const [key, val] of Object.entries(obj)) {
    const fullKey = prefix ? prefix + '.' + key : key;
    if (val !== null && typeof val === 'object' && !Array.isArray(val)) {
      Object.assign(result, flattenKeys(val, fullKey));
    } else {
      result[fullKey] = val;
    }
  }
  return result;
}
